from pathlib import Path
import base64
import gzip

FILES = {
    "internal/runtimeintegrity/manifest.go": "",
    "internal/runtimeintegrity/tree_linux.go": "",
    "internal/runtimeintegrity/manifest_test.go": ""
}

for relative, encoded in FILES.items():
    path = Path(relative)
    if path.exists():
        raise SystemExit(f"refusing to overwrite existing {relative}")
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(gzip.decompress(base64.b64decode(encoded)))

parity = Path("docs/upstream-rufus-parity.json")
text = parity.read_text(encoding="utf-8")
old = '"notes": "The 0.11 development line exposes descriptor-rooted CLI and GTK validation of fallback loaders, PE architecture and EFI subsystem fields, bounded SBAT metadata, optional DBX hash/certificate revocations, and shim-compatible comparison against a trusted local or running-firmware SbatLevel. Complete boot-chain reference resolution remains planned."'
new = '"notes": "The existing 0.11 CLI and GTK UEFI structural/Secure Boot analyzer is distinct from upstream runtime validation. A descriptor-rooted uefi-md5sum-compatible manifest generator, strict parser, and full-tree verifier are now implemented; bootloader provenance, transactional fallback-loader wrapping, QEMU chainload tests, and physical qualification remain planned."'
if text.count(old) != 1:
    raise SystemExit(f"parity wording matched {text.count(old)} times")
parity.write_text(text.replace(old, new, 1), encoding="utf-8")

readme = Path("README.md")
text = readme.read_text(encoding="utf-8")
anchor = "The single visible graphical application entry supplies the ordinary writer and the persistent-live action while retaining separate guarded helpers internally. The main window also provides a read-only **Validate UEFI Media…** dialog for mounted or extracted media; it reports fallback-loader, PE/EFI, DBX, and SBAT results, and can compare against either a trusted local SbatLevel CSV or the running shim firmware SBAT level without changing the write path.\n"
addition = anchor + "\nThat pre-boot structural/Secure Boot analysis is separate from Rufus's boot-time media-integrity option. The 0.11 development line now includes the descriptor-safe `uefi-md5sum` manifest foundation; it does not yet replace or chainload the media fallback loader.\n"
if text.count(anchor) != 1:
    raise SystemExit(f"README anchor matched {text.count(anchor)} times")
readme.write_text(text.replace(anchor, addition, 1), encoding="utf-8")

provenance = Path("docs/uefi-runtime-integrity.md")
provenance.write_text("""# UEFI runtime media integrity\n\nRufus upstream's **Enable runtime UEFI media validation** option installs [uefi-md5sum](https://github.com/pbatard/uefi-md5sum), which verifies a root `md5sum.txt` at boot and then chainloads the original removable-media fallback loader. This differs from RufusArm64's read-only UEFI structural and Secure Boot analyzer.\n\n## Foundation implemented in 0.11 development\n\nThe `internal/runtimeintegrity` package generates, parses, and verifies the strict interoperable subset of `md5sum.txt` used by uefi-md5sum. It uses descriptor-rooted, no-symlink traversal, stable inode/type/size/time checks, deterministic `./path` ordering, lowercase MD5 records, and the `md5sum_totalbytes` progress extension. Verification reports changed, missing, unexpected, and total-byte mismatches.\n\nThe parser and generator retain upstream's published safety ceilings: a 64 MiB manifest, 100,000 records, and 512-byte paths. MD5 is used only because it is the on-media interoperability contract; RufusArm64 continues to use SHA-256 for download, source-identity, and destructive-write assurance.\n\n## Not yet enabled\n\nThis foundation does not rename or replace a fallback loader. Bootloader source pinning and reproducible ARM64 builds, transactional installation and rollback, GUI integration, QEMU chainload tests, and physical Secure Boot qualification remain separate reviewed gates.\n""", encoding="utf-8")
